request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?language ?modelName ?modelId ?definitions
WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "67e70970f0404a7e87122700ad26d87b" .
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName ;
         tai:normalizedId ?modelId .
  ?definitions a bboExt:Definitions ;
               tai:belongsTo ?model ;
               bboExt:expressionLanguage ?language .
  OPTIONAL { ?definitions bboExt:typeLanguage ?typeLanguage . }
  OPTIONAL { ?definitions bboExt:exporter ?definitions . }
}
LIMIT 25
